import * as ewe from "@eyeo/webext-ad-filtering-solution";
const memoryStorage = new Map();
const useMemoryStorage = !("session" in browser.storage);
export class SessionStorage {
    constructor(namespace) {
        this._namespace = namespace;
        this._queue = Promise.resolve();
    }
    _getGlobalKey(key) {
        return `session:${this._namespace}:${key}`;
    }
    async delete(key) {
        const globalKey = this._getGlobalKey(key);
        if (useMemoryStorage)
            return memoryStorage.delete(globalKey);
        return browser.storage.session.remove(globalKey);
    }
    async get(key) {
        const globalKey = this._getGlobalKey(key);
        if (useMemoryStorage)
            return memoryStorage.get(globalKey);
        let storage;
        try {
            storage = await browser.storage.session.get(globalKey);
        }
        catch (error) {
            throw Error(`Error occured when retrieving session storage entry for ${globalKey} key:
        ${error.message}`);
        }
        return storage[globalKey];
    }
    async set(key, value) {
        const globalKey = this._getGlobalKey(key);
        if (useMemoryStorage) {
            memoryStorage.set(globalKey, value);
            return;
        }
        try {
            await browser.storage.session.set({ [globalKey]: value });
        }
        catch (error) {
            throw Error(`Error occured when setting session storage entry for ${globalKey} key:
        ${error.message}`);
        }
    }
    async transaction(fn) {
        this._queue = this._queue
            .catch((e) => ewe.sentry.reportError(e))
            .then(fn);
        return this._queue;
    }
}
