import { getDebugInformation } from "@eyeo-fragments/debug-information/background";
import { getInstallationId } from "../../id/background";
import { Prefs } from "../../../adblockpluschrome/lib/prefs";
import { getPremiumState } from "../../premium/background";
import { addTrustedMessageTypes, port } from "../../core/messaging/background";
const getDebugLicenseInfo = async () => {
    const [{ isActive }, installationId] = await Promise.all([
        getPremiumState(),
        getInstallationId()
    ]);
    return { isActive, installationId };
};
export const getDebugInfo = async function () {
    await Prefs.untilLoaded;
    const prefs = Prefs.toJSON();
    const licenseInformation = await getDebugLicenseInfo();
    return await getDebugInformation({
        licenseInformation,
        prefs
    });
};
async function handleGetDebugInfoMessage(message, sender) {
    return await getDebugInfo();
}
export function start() {
    port.on("debug.getInfo", handleGetDebugInfoMessage);
    addTrustedMessageTypes(null, ["debug.getInfo"]);
}
