export function getPerformanceTimings() {
    return {
        marks: performance.getEntriesByType("mark").map(entry => {
            return {
                name: entry.name,
                startTime: entry.startTime
            };
        }),
        measures: performance.getEntriesByType("measure").map(entry => {
            return {
                name: entry.name,
                startTime: entry.startTime,
                duration: entry.duration
            };
        })
    };
}
